import { NgModule } from '@angular/core';
import { ExtraOptions, Routes, RouterModule } from '@angular/router';

const routes: Routes = [];

const routerOptions: ExtraOptions = {
  scrollPositionRestoration: 'enabled', // Optional: restores position on backward navigation
  anchorScrolling: 'enabled', // Enables scrolling to the element with the ID in the fragment
  onSameUrlNavigation: 'reload' // Optional: reloads if fragment changes on the same URL
};
@NgModule({
  imports: [RouterModule.forRoot(routes, routerOptions)],
  exports: [RouterModule]
})
export class AppRoutingModule { }
