import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import emailjs from 'emailjs-com';
import { ToastrService } from 'ngx-toastr';

@Component({
  selector: 'app-contact',
  templateUrl: './contact.component.html',
  styleUrls: ['./contact.component.css']
})
export class ContactComponent implements OnInit {
  contactForm: FormGroup;
  isLoading = false;
  successMessage = '';
  errorMessage = '';
  constructor(private fb: FormBuilder,  private toastr : ToastrService) { this.contactForm = this.fb.group({
      name: ['', Validators.required],
      email: ['', [Validators.required, Validators.email]],
      company: ['', Validators.required],
      phone: ['', Validators.required],
      message: ['', Validators.required] });
  }

  ngOnInit(): void {
  }

  sendMessage() {
    if (this.contactForm.invalid) {
      this.contactForm.markAllAsTouched();
      return;
    }

    this.isLoading = true;

    emailjs.send(
      'service_6oqmj3c',
      'template_3tzd1m5',
      this.contactForm.value,
      '3yEYGGc_cexpPHsLh'
    ).then(() => {
      this.successMessage = 'Message sent successfully!';
      this.contactForm.reset();
      this.isLoading = false;
      this.toastr.success("Message sent successfully!","successfully")
    }).catch(() => {
      this.errorMessage = 'Failed to send message. Try again.';
      this.toastr.error("Failed to send message. Try again.","Failed")
      this.isLoading = false;
    });
  }

}
